INSERT INTO QUESTION_ANALYSIS (
    QUESTION_ID, USER_ID, ANALYSIS_CONTENT, ANALYSIS_IMAGE_BASE64, CREATED_TIME, UPDATED_TIME
) VALUES (
    #{questionId}, #{userId}, #{analysisContent}, #{analysisImageBase64}, #{createdTime}, #{updatedTime}
)
ON DUPLICATE KEY UPDATE
    ANALYSIS_CONTENT = VALUES(ANALYSIS_CONTENT),
    ANALYSIS_IMAGE_BASE64 = VALUES(ANALYSIS_IMAGE_BASE64),
    UPDATED_TIME = VALUES(UPDATED_TIME)
